using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class NotificationConfiguration : IEntityTypeConfiguration<Notification>{public void Configure(EntityTypeBuilder<Notification> builder){builder.ToTable("notifications");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("notification_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Type).HasMaxLength(40).IsRequired();builder.Property(e => e.Priority).HasConversion<string>().HasMaxLength(5);builder.Property(e => e.Title).HasMaxLength(150).IsRequired();builder.Property(e => e.Body).IsRequired();builder.Property(e => e.Metadata).HasColumnType("jsonb");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.CreatedAt });}}
